<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;">King Khalid International Airport (RUH)</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;text-align:center;">~30 min</td></tr>
<tr><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Diplomatic Quarter</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;text-align:center;">~15 min</td></tr>
<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Al Masmak Fortress (Old Riyadh)</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;text-align:center;">~20 min</td></tr>
