<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Saturday – Thursday</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;">8:00 AM – 8:00 PM</td></tr>
