<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Central Riyadh</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;text-align:center;">~1 hr 30 min</td></tr>
